import { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';

const ROLES = ['admin', 'community_admin', 'student', 'external'];
const STATUSES = ['pending', 'approved', 'rejected'];

export default function AdminUsers() {
  const [searchParams] = useSearchParams();
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    role: searchParams.get('role') || '',
    status: searchParams.get('status') || '',
    page: 1,
  });
  const [total, setTotal] = useState(0);
  const [pages, setPages] = useState(1);
  const [searchTerm, setSearchTerm] = useState('');

  const [editingUser, setEditingUser] = useState(null);
  const [editForm, setEditForm]       = useState({});
  const [saving, setSaving]           = useState(false);

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (filters.role) params.set('role', filters.role);
      if (filters.status) params.set('status', filters.status);
      params.set('page', filters.page);
      params.set('limit', 15);
      const res = await api.get(`/users?${params}`);
      setUsers(res.data.data);
      setTotal(res.data.total);
      setPages(res.data.pages);
    } catch {
      toast.error('Failed to load users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchUsers(); }, [filters]);

  const approveUser = async (id, name) => {
    try {
      await api.put(`/users/${id}/approve`);
      toast.success(`${name} approved`);
      fetchUsers();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const rejectUser = async (id, name) => {
    const reason = prompt(`Reason for rejecting ${name}:`);
    if (reason === null) return;
    try {
      await api.put(`/users/${id}/reject`, { reason });
      toast.success(`${name} rejected`);
      fetchUsers();
    } catch { toast.error('Failed'); }
  };

  const openEdit = (u) => {
    setEditingUser(u);
    setEditForm({ name: u.name || '', email: u.email || '', role: u.role || 'student', status: u.status || 'pending' });
  };

  const saveEdit = async () => {
    setSaving(true);
    try {
      await api.put(`/users/${editingUser._id}`, editForm);
      toast.success('User updated');
      setEditingUser(null);
      fetchUsers();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save');
    } finally {
      setSaving(false);
    }
  };

  const deleteUser = async (id, name) => {
    if (!window.confirm(`Delete user ${name}? This cannot be undone.`)) return;
    try {
      await api.delete(`/users/${id}`);
      toast.success('User deleted');
      fetchUsers();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const stats = {
    total: total,
    pending: users.filter(u => u.status === 'pending').length,
    approved: users.filter(u => u.status === 'approved').length,
    rejected: users.filter(u => u.status === 'rejected').length,
    admin: users.filter(u => u.role === 'admin').length,
    communityAdmin: users.filter(u => u.role === 'community_admin').length,
    student: users.filter(u => u.role === 'student').length,
  };

  const filteredUsers = users.filter(u =>
    u.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    u.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    u.itNumber?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen p-6 md:p-10 font-sans text-slate-100 relative overflow-hidden bg-[#020617]">
      {/* Dynamic Background Effects */}
      <div className="absolute top-1/4 left-0 w-[500px] h-[500px] bg-purple-600/10 rounded-full mix-blend-screen filter blur-[150px] animate-blob pointer-events-none" />
      <div className="absolute bottom-1/4 right-0 w-[600px] h-[600px] bg-cyan-600/10 rounded-full mix-blend-screen filter blur-[120px] animation-delay-4000 animate-blob pointer-events-none" />

      <div className="max-w-7xl mx-auto relative z-10 space-y-10">

        {/* Header */}
        <header className="glass-dark rounded-3xl p-8 border border-white/10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative group overflow-hidden shadow-2xl">
          <div className="absolute inset-0 bg-gradient-to-r from-cyan-500/5 to-purple-500/5 opacity-0 group-hover:opacity-100 transition-opacity duration-700 pointer-events-none" />

          <div className="flex items-center gap-6 relative z-10">
            <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-pink-500 to-purple-500 p-[2px] shadow-[0_0_20px_rgba(236,72,153,0.4)]">
              <div className="w-full h-full bg-slate-950 rounded-[14px] flex items-center justify-center text-3xl">
                👥
              </div>
            </div>
            <div>
              <h2 className="text-3xl md:text-4xl font-black mb-1 tracking-tight">
                USER <span className="text-transparent bg-clip-text bg-gradient-to-r from-pink-400 to-purple-500">MANAGEMENT</span>
              </h2>
              <div className="flex items-center gap-4 flex-wrap mt-2">
                <span className="px-3 py-1 bg-pink-500/10 border border-pink-500/20 text-pink-400 text-xs font-bold rounded-full flex items-center gap-1.5 shadow-[0_0_10px_rgba(236,72,153,0.1)]">
                  👥 {total} Total Users Network
                </span>
                {stats.pending > 0 && (
                  <span className="px-3 py-1 bg-amber-500/10 border border-amber-500/20 text-amber-500 text-xs font-bold rounded-full flex items-center gap-1.5 animate-pulse shadow-[0_0_10px_rgba(245,158,11,0.1)]">
                    ⏳ {stats.pending} Applications Pending
                  </span>
                )}
              </div>
            </div>
          </div>

          <div className="flex gap-4 relative z-10">
            <Link to="/admin" className="glass hover:bg-white/10 px-6 py-3 rounded-full font-bold text-white transition-all hover:-translate-y-1 border border-white/10 flex items-center gap-2">
              ← Dashboard
            </Link>
          </div>
        </header>

        {/* Stats Grid */}
        <div className="grid grid-cols-2 lg:grid-cols-6 gap-4">
          {[
            { label: 'Total', value: stats.total, icon: '👥', color: 'text-cyan-400' },
            { label: 'Pending', value: stats.pending, icon: '⏳', color: 'text-amber-400' },
            { label: 'Approved', value: stats.approved, icon: '✓', color: 'text-emerald-400' },
            { label: 'Rejected', value: stats.rejected, icon: '✗', color: 'text-rose-400' },
            { label: 'Admins', value: stats.admin, icon: '👑', color: 'text-purple-400' },
            { label: 'Students', value: stats.student, icon: '🎓', color: 'text-pink-400' },
          ].map((s, i) => (
            <div key={i} className="glass-dark rounded-2xl p-5 border border-white/5 text-center relative group overflow-hidden transition-all duration-300 hover:bg-white/5 hover:border-white/20 hover:-translate-y-1">
              <div className="absolute top-0 right-0 p-2 opacity-5 drop-shadow-lg scale-150 transition-transform duration-500 group-hover:scale-[2] pointer-events-none">{s.icon}</div>
              <div className="relative z-10 flex flex-col gap-1 items-center justify-center h-full">
                <span className="text-2xl drop-shadow-md mb-1">{s.icon}</span>
                <span className={`text-3xl font-black tracking-tight ${s.color}`}>{s.value}</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none">{s.label}</span>
              </div>
            </div>
          ))}
        </div>

        {/* Filters Toolbar */}
        <div className="glass-dark rounded-2xl p-4 md:p-6 border border-white/5 flex flex-col md:flex-row flex-wrap justify-between items-center gap-6">
          <div className="flex flex-col sm:flex-row gap-4 sm:gap-6 w-full md:w-auto">

            {/* Role Filter */}
            <div className="flex flex-wrap gap-2">
              {[
                { id: '', label: 'All Roles', icon: '👤' },
                { id: 'admin', label: 'Admin', icon: '👑' },
                { id: 'community_admin', label: 'Comm. Admin', icon: '🏛️' },
                { id: 'student', label: 'Student', icon: '🎓' },
              ].map((f) => (
                <button
                  key={f.id}
                  onClick={() => setFilters(p => ({ ...p, role: f.id, page: 1 }))}
                  className={`px-4 py-2 rounded-xl text-xs font-bold uppercase tracking-widest transition-all border flex items-center gap-1.5 ${filters.role === f.id ? `bg-white/10 text-cyan-400 border-cyan-500/30 shadow-lg` : 'border-transparent text-slate-400 hover:bg-white/5 hover:text-white'}`}
                >
                  <span className="text-lg leading-none opacity-80">{f.icon}</span> <span className="mt-0.5">{f.label}</span>
                </button>
              ))}
            </div>

            <div className="hidden sm:block w-[1px] bg-white/10 self-stretch my-2" />

            {/* Status Filter */}
            <div className="flex flex-wrap gap-2">
              {[
                { id: '', label: 'All Status' },
                { id: 'pending', label: 'Pending' },
                { id: 'approved', label: 'Approved' },
                { id: 'rejected', label: 'Rejected' },
              ].map((f) => (
                <button
                  key={f.id}
                  onClick={() => setFilters(p => ({ ...p, status: f.id, page: 1 }))}
                  className={`px-4 py-2 rounded-xl text-xs font-bold uppercase tracking-widest transition-all border ${filters.status === f.id ? `bg-white/10 text-cyan-400 border-cyan-500/30 shadow-lg` : 'border-transparent text-slate-400 hover:bg-white/5 hover:text-white'}`}
                >
                  {f.label}
                </button>
              ))}
            </div>
          </div>

          <div className="relative w-full md:w-80 lg:w-96 group">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-hover:text-cyan-400 transition-colors">🔍</span>
            <input type="text" placeholder="Search by name, email, or IT number..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full bg-black/40 border border-white/10 rounded-xl pl-12 pr-10 py-3 text-white focus:outline-none focus:border-cyan-500/50 focus:ring-1 focus:ring-cyan-500/50 transition-all font-medium text-sm" />
            {searchTerm && (
              <button onClick={() => setSearchTerm('')} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white transition-colors">✕</button>
            )}
          </div>
        </div>

        {/* Users Grid */}
        {loading ? (
          <div className="flex flex-col items-center justify-center min-h-[40vh] space-y-4">
            <div className="w-12 h-12 border-4 border-purple-500/30 border-t-purple-500 rounded-full animate-spin" />
            <span className="text-purple-400 font-medium tracking-widest uppercase text-sm animate-pulse">Scanning User Database...</span>
          </div>
        ) : filteredUsers.length === 0 ? (
          <div className="flex flex-col items-center justify-center text-center p-16 glass-dark rounded-3xl border border-white/5 opacity-80 backdrop-blur-3xl shadow-2xl">
            <span className="text-6xl mb-6 drop-shadow-2xl opacity-50">👥</span>
            <h3 className="text-3xl font-black mb-3 text-white">No users found</h3>
            <p className="text-slate-400 font-medium max-w-md">The search query and filters did not match any accounts.</p>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredUsers.map(u => {
                const isPending = u.status === 'pending';
                const isApproved = u.status === 'approved';
                const statusColor = isPending ? 'amber-500' : isApproved ? 'emerald-500' : 'rose-500';

                const roleColor = u.role === 'admin' ? 'purple-500' : u.role === 'community_admin' ? 'cyan-500' : 'slate-500';

                return (
                  <div key={u._id} className="glass-dark border border-white/5 rounded-3xl overflow-hidden shadow-xl hover:shadow-[0_20px_50px_rgba(0,0,0,0.5)] transition-all duration-300 hover:-translate-y-1 group flex flex-col relative w-full h-full p-6">
                    <div className={`absolute top-0 w-full left-0 h-1 bg-gradient-to-r from-${statusColor}/20 via-${statusColor} to-${statusColor}/20 opacity-80`} />
                    <div className="flex items-center gap-5 mb-6">
                      <div className={`w-16 h-16 rounded-2xl bg-gradient-to-br from-${roleColor}/20 to-${roleColor}/5 flex items-center justify-center text-3xl shrink-0 shadow-lg border border-${roleColor}/20 text-${roleColor} font-black uppercase overflow-hidden relative group-hover:scale-105 transition-transform`}>
                        {u.name?.charAt(0)}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex justify-between items-start mb-1 gap-2 flex-wrap">
                           <h3 className="font-bold text-lg text-white group-hover:text-pink-400 transition-colors leading-tight line-clamp-1 truncate pr-2">{u.name}</h3>
                           <span className={`px-2 py-0.5 text-[9px] font-black uppercase tracking-widest rounded bg-${statusColor}/10 text-${statusColor} border border-${statusColor}/20 whitespace-nowrap`}>
                             {u.status}
                           </span>
                        </div>
                        <div className="text-slate-400 text-xs truncate mb-2">{u.email}</div>
                        <span className={`px-2.5 py-1 text-[10px] font-black uppercase tracking-widest rounded-md bg-${roleColor}/10 text-${roleColor} border border-${roleColor}/20 inline-block`}>
                          {u.role.replace('_', ' ')}
                        </span>
                      </div>
                    </div>

                    <div className="space-y-3 mb-6 p-4 rounded-xl bg-black/30 border border-white/5 text-sm flex-1">
                      {u.itNumber && (
                        <div className="flex items-center gap-3 w-full">
                          <span className="text-cyan-400 text-lg opacity-80 mt-1">🆔</span>
                          <div className="flex flex-col min-w-0 flex-1">
                            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest leading-none mb-1">IT Number</span>
                            <span className="font-mono text-cyan-400 font-bold truncate tracking-wider">{u.itNumber}</span>
                          </div>
                        </div>
                      )}

                      {(u.role === 'student' || u.role === 'community_admin') && (
                        <div className="flex flex-col min-w-0 border-t border-white/5 pt-3 mt-3 w-full">
                          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest leading-none mb-2">Community Link</span>
                          <span className="text-slate-300 font-medium truncate flex items-center gap-2">
                            <span className="text-purple-400 text-[14px]">🏛️</span> 
                            {u.role === 'student' ? (u.requestedCommunity?.name || '—') : (u.managedCommunity?.name || u.communityName || '—')}
                          </span>
                        </div>
                      )}

                      {u.role === 'community_admin' && isPending && u.communityCategory && (
                         <div className="flex flex-col min-w-0 border-t border-white/5 pt-3 mt-3 w-full">
                          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest leading-none mb-2">Category</span>
                          <span className="text-slate-300 font-medium truncate flex items-center gap-2">
                             <span className="text-emerald-400 text-[14px]">📂</span> {u.communityCategory}
                          </span>
                        </div>
                      )}

                      {u.rejectionReason && (
                        <div className="border-t border-white/5 pt-3 mt-3 w-full flex gap-3 text-sm p-2 rounded bg-rose-500/10 border-l-2 border-l-rose-500">
                          <span className="text-rose-400 opacity-80 mt-0.5">⚠️</span>
                          <div className="flex flex-col flex-1 min-w-0">
                            <span className="text-[10px] font-black text-rose-500/80 uppercase tracking-widest leading-none mb-1">Rejection Reason</span>
                            <span className="text-rose-300/90 leading-tight italic line-clamp-2">"{u.rejectionReason}"</span>
                          </div>
                        </div>
                      )}

                    </div>

                    <div className="mt-auto space-y-2">
                      <div className="flex items-center justify-between px-2 text-[10px] text-slate-500 font-bold uppercase tracking-widest mb-4">
                         <span>Registered</span>
                         <span>{new Date(u.createdAt).toLocaleDateString()}</span>
                      </div>
                      <div className="flex gap-3">
                        {isPending && (
                          <>
                            <button onClick={() => approveUser(u._id, u.name)} className="flex-1 py-2.5 rounded-xl bg-emerald-500/10 border border-emerald-500/20 font-bold text-xs uppercase tracking-widest text-emerald-400 hover:bg-emerald-500/20 hover:-translate-y-0.5 transition-all flex justify-center items-center gap-2">✓ Accept</button>
                            <button onClick={() => rejectUser(u._id, u.name)} className="flex-1 py-2.5 rounded-xl bg-rose-500/10 border border-rose-500/20 font-bold text-xs uppercase tracking-widest text-rose-400 hover:bg-rose-500/20 hover:-translate-y-0.5 transition-all flex justify-center items-center gap-2">✗ Decline</button>
                          </>
                        )}
                        {u.role !== 'admin' && (
                          <button onClick={() => deleteUser(u._id, u.name)} className={`py-2.5 px-4 rounded-xl bg-slate-800 border border-slate-700 font-bold text-xs uppercase tracking-widest text-rose-500 hover:text-white hover:bg-rose-500 hover:border-rose-500 transition-all flex justify-center items-center gap-2 ${isPending ? 'flex-none' : 'flex-1 w-full'}`}>
                            🗑 Delete
                          </button>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Pagination */}
            {pages > 1 && (
              <div className="flex justify-center items-center gap-4 mt-12 py-6 border-t border-white/5">
                <button
                  onClick={() => setFilters(prev => ({ ...prev, page: Math.max(1, prev.page - 1) }))}
                  disabled={filters.page === 1}
                  className="px-6 py-3 rounded-full font-bold text-sm tracking-widest uppercase flex items-center gap-2 glass transition-all disabled:opacity-50 disabled:cursor-not-allowed hover:bg-white/10"
                >
                  ← Previous
                </button>
                <div className="flex gap-2 text-sm font-bold bg-black/40 p-1.5 rounded-full border border-white/10 shadow-inner overflow-hidden max-w-full">
                  {Array.from({ length: Math.min(7, pages) }, (_, i) => {
                    let pageNum;
                    if (pages <= 7) pageNum = i + 1;
                    else if (filters.page <= 4) pageNum = i + 1;
                    else if (filters.page >= pages - 3) pageNum = pages - 6 + i;
                    else pageNum = filters.page - 3 + i;

                    return (
                      <button
                        key={pageNum}
                        onClick={() => setFilters(prev => ({ ...prev, page: pageNum }))}
                        className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${filters.page === pageNum ? 'bg-cyan-500 text-black shadow-[0_0_15px_rgba(6,182,212,0.5)] scale-110' : 'text-slate-400 hover:bg-white/10 hover:text-white'}`}
                      >
                        {pageNum}
                      </button>
                    );
                  })}
                </div>
                <button
                  onClick={() => setFilters(prev => ({ ...prev, page: Math.min(pages, prev.page + 1) }))}
                  disabled={filters.page === pages}
                  className="px-6 py-3 rounded-full font-bold text-sm tracking-widest uppercase flex items-center gap-2 glass transition-all disabled:opacity-50 disabled:cursor-not-allowed hover:bg-white/10"
                >
                  Next →
                </button>
              </div>
            )}
          </div>
        )}

      </div>
    </div>
  );
}
